// ⚙️ EDIT THESE ONCE. (HMAC secret must be inline — Code nodes can't read credentials.)
const cfg = {
  hmac_secret: 'PASTE_ARQFLOW_HMAC_SECRET_HERE',       // == platform N8N_WEBHOOK_SECRET
  template_starter: 'PASTE_STARTER_TEMPLATE_WORKFLOW_ID',
  template_business: 'PASTE_BUSINESS_TEMPLATE_WORKFLOW_ID',
  template_enterprise: 'PASTE_ENTERPRISE_TEMPLATE_WORKFLOW_ID'
};
const item = $input.first().json;
return { json: { body: item.body, headers: item.headers || {}, cfg } };

const crypto = require('crypto');
const c = $('FACTORY_CONFIG').first().json;
const body = c.body, headers = c.headers || {};
if (!body) throw new Error('Empty payload');
const secret = c.cfg.hmac_secret || '';
const incoming = headers['x-arqflow-signature'] || headers['X-ArqFlow-Signature'] || '';
const raw = JSON.stringify(body);
const expected = crypto.createHmac('sha256', secret).update(raw).digest('hex');
let ok = false;
try { ok = crypto.timingSafeEqual(Buffer.from(incoming, 'hex'), Buffer.from(expected, 'hex')); } catch (e) { ok = false; }
if (!ok) throw new Error('Invalid signature');
const required = ['business_id', 'order_id', 'plan_id', 'business', 'callback_url'];
const missing = required.filter(k => !body[k]);
if (missing.length) throw new Error('Missing required fields: ' + missing.join(', '));
return { json: { body } };

const b = $('VALIDATE_SIGNATURE').first().json.body;
const cfg = $('FACTORY_CONFIG').first().json.cfg;
const plan = b.plan || {};
const tier = String(b.plan_id || plan.tier || 'starter').toLowerCase();
const templateMap = { starter: cfg.template_starter, business: cfg.template_business, enterprise: cfg.template_enterprise };
const template_id = templateMap[tier] || cfg.template_starter;
const slug = String(b.order_id).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '');
return { json: {
  business_id: b.business_id, order_id: b.order_id, plan_id: tier, tier,
  template_id, instance_name: 'arq-' + slug, webhook_path: 'bot-' + slug, callback_url: b.callback_url,
  business: b.business, content: b.content || {},
  model: plan.model || 'anthropic/claude-sonnet-4.5',
  fallback_model: plan.fallback_model || 'anthropic/claude-haiku-4.5',
  max_tokens: plan.max_tokens || 1024, memory_window: plan.memory_window || 10,
  message_limit: plan.message_limit || 5000, tools: plan.tools || [], media_support: plan.media_support || ['text']
} };

const s = $('SELECT_TEMPLATE').first().json;
const b = s.business || {}, c = s.content || {};
const arr = (x) => Array.isArray(x) ? x : [];
const products = arr(c.products).map(p => `- ${p.name}${p.price_egp != null ? ' (' + p.price_egp + ' ج.م)' : ''}${p.description ? ': ' + p.description : ''}`).join('
');
const services = arr(c.services).map(p => `- ${p.name}${p.price_egp != null ? ' (' + p.price_egp + ' ج.م)' : ''}${p.description ? ': ' + p.description : ''}`).join('
');
const faqs = arr(c.faqs).map(f => `س: ${f.question || ''}
ج: ${f.answer || ''}`).join('

');
const langs = arr(b.languages).join('، ') || 'العربية';
let p = '';
p += `# هوية البوت
أنت المساعد الذكي الرسمي لـ "${b.business_name || ''}" (${b.business_type || 'نشاط تجاري'}).
`;
if (b.description) p += `${b.description}
`;
p += `
# الشخصية والأسلوب
- نبرة الصوت: ${b.tone_of_voice || 'ودود ومحترف'}.
`;
if (b.assistant_personality) p += `- الشخصية: ${b.assistant_personality}
`;
p += `- اللغات: ${langs}.
`;
if (b.greeting_message) p += `- رسالة الترحيب: ${b.greeting_message}
`;
p += `
# قواعد صارمة (Hard Rules)
- لا تخترع معلومات غير موجودة في قاعدة المعرفة.
- عند عدم المعرفة: ${b.fallback_behavior || 'حوّل العميل لموظف بشري'}.
- لا تشارك بيانات عملاء آخرين.
`;
if (b.working_hours) p += `
# مواعيد العمل
${b.working_hours}
`;
if (b.location) p += `
# الموقع
${b.location}
`;
if (arr(b.payment_methods).length) p += `
# طرق الدفع
${arr(b.payment_methods).join('، ')}
`;
if (b.delivery_info) p += `
# التوصيل
${b.delivery_info}
`;
if (b.return_policy) p += `
# سياسة الاسترجاع
${b.return_policy}
`;
if (b.order_instructions) p += `
# تعليمات الطلب
${b.order_instructions}
`;
if (b.policy) p += `
# السياسات
${b.policy}
`;
if (products) p += `
# المنتجات
${products}
`;
if (services) p += `
# الخدمات
${services}
`;
if (b.knowledge_base) p += `
# قاعدة المعرفة
${b.knowledge_base}
`;
if (faqs) p += `
# الأسئلة الشائعة
${faqs}
`;
return { json: { ...s, system_prompt: p.trim() } };

const s = $('BUILD_SYSTEM_PROMPT').first().json;
const b = s.business || {};
const admin_whatsapp = String(b.contact_number || b.whatsapp_number || '').replace(/[^0-9]/g, '');
const tenant_config = {
  business_id: s.business_id, order_id: s.order_id, plan_id: s.plan_id,
  business_name: b.business_name || '', instance_name: s.instance_name, webhook_path: s.webhook_path,
  admin_whatsapp, model: s.model, fallback_model: s.fallback_model, max_tokens: s.max_tokens,
  memory_window: s.memory_window, message_limit: s.message_limit, tools: s.tools,
  media_support: s.media_support, system_prompt: s.system_prompt
};
const replacements = {
  '__BUSINESS_ID__': s.business_id, '__ORDER_ID__': s.order_id, '__PLAN_ID__': s.plan_id,
  '__BUSINESS_NAME__': b.business_name || '', '__INSTANCE_NAME__': s.instance_name,
  '__WEBHOOK_PATH__': s.webhook_path, '__ADMIN_WHATSAPP__': admin_whatsapp,
  '__MODEL__': s.model, '__FALLBACK_MODEL__': s.fallback_model, '__MAX_TOKENS__': String(s.max_tokens),
  '__MEMORY_WINDOW__': String(s.memory_window), '__MESSAGE_LIMIT__': String(s.message_limit),
  '__SYSTEM_PROMPT__': s.system_prompt, '__TENANT_CONFIG_JSON__': JSON.stringify(tenant_config)
};
return { json: { business_id: s.business_id, order_id: s.order_id, plan_id: s.plan_id,
  business_name: b.business_name || '', instance_name: s.instance_name, webhook_path: s.webhook_path,
  callback_url: s.callback_url, system_prompt: s.system_prompt, template_id: s.template_id,
  tenant_config, replacements } };

const inj = $('INJECTION_ENGINE').first().json;
const tpl = $input.first().json;
if (!tpl || !Array.isArray(tpl.nodes)) {
  return { json: { provision_ok: false, error: 'Template fetch failed (check FACTORY_CONFIG template IDs + n8n API credential)' } };
}
function jesc(v) {
  return String(v == null ? '' : v).replace(/\\/g, '\\\\').replace(/"/g, '\\"')
    .replace(/\n/g, '\\n').replace(/\r/g, '\\r').replace(/\t/g, '\\t');
}
let wf = { name: '🤖 Arq | ' + inj.business_name + ' (' + inj.order_id + ')',
           nodes: tpl.nodes, connections: tpl.connections, settings: tpl.settings || { executionOrder: 'v1' } };
let str = JSON.stringify(wf);
for (const [k, v] of Object.entries(inj.replacements)) { str = str.split(k).join(jesc(v)); }
try { wf = JSON.parse(str); } catch (e) { return { json: { provision_ok: false, error: 'Replacement produced invalid JSON: ' + e.message } }; }
return { json: { provision_ok: true, workflow_payload: wf } };

const inj = $('INJECTION_ENGINE').first().json;
const apply = $('APPLY_REPLACEMENTS').first().json;
let created = {}; try { created = $('CREATE_WORKFLOW').first().json || {}; } catch (e) {}
const workflow_id = created && created.id ? created.id : null;
const provision_ok = apply.provision_ok === true && !!workflow_id;
return { json: { business_id: inj.business_id, order_id: inj.order_id, callback_url: inj.callback_url,
  instance_name: inj.instance_name, webhook_path: inj.webhook_path, system_prompt: inj.system_prompt,
  tenant_config: inj.tenant_config, workflow_id, provision_ok,
  bot_webhook_url: 'https://bc1b1373.kube-ops.com/webhook/' + inj.webhook_path,
  error: apply.error || (workflow_id ? null : 'Workflow creation failed (check n8n API credential)') } };

const crypto = require('crypto');
const m = $('EXTRACT_META').first().json;
const secret = $('FACTORY_CONFIG').first().json.cfg.hmac_secret || '';
const payload = { event: 'provision_complete', business_id: m.business_id, workflow_id: m.workflow_id,
  instance_name: m.instance_name, webhook_path: m.webhook_path, system_prompt: m.system_prompt, qr_sent: true };
const sig = crypto.createHmac('sha256', secret).update(JSON.stringify(payload)).digest('hex');
return { json: { callback_url: m.callback_url, signature: sig, payload } };

const crypto = require('crypto');
const m = $('EXTRACT_META').first().json;
const secret = $('FACTORY_CONFIG').first().json.cfg.hmac_secret || '';
const payload = { event: 'provision_failed', business_id: m.business_id, error: m.error || 'Provisioning failed' };
const sig = crypto.createHmac('sha256', secret).update(JSON.stringify(payload)).digest('hex');
return { json: { callback_url: m.callback_url, signature: sig, payload } };
